SET NOCOUNT ON;

IF COL_LENGTH('ai_agent_runs','effective_priority') IS NULL ALTER TABLE ai_agent_runs ADD effective_priority NVARCHAR(40) NULL;
IF COL_LENGTH('ai_agent_runs','current_step_code') IS NULL ALTER TABLE ai_agent_runs ADD current_step_code NVARCHAR(160) NULL;
IF COL_LENGTH('ai_agent_runs','prompt_version_id') IS NULL ALTER TABLE ai_agent_runs ADD prompt_version_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_agent_runs','queue_name') IS NULL ALTER TABLE ai_agent_runs ADD queue_name NVARCHAR(180) NULL;
IF COL_LENGTH('ai_agent_runs','worker_id') IS NULL ALTER TABLE ai_agent_runs ADD worker_id NVARCHAR(180) NULL;
IF COL_LENGTH('ai_agent_runs','quality_score') IS NULL ALTER TABLE ai_agent_runs ADD quality_score DECIMAL(8,2) NULL;
IF COL_LENGTH('ai_agent_runs','risk_score') IS NULL ALTER TABLE ai_agent_runs ADD risk_score DECIMAL(8,2) NULL;
IF COL_LENGTH('ai_agent_runs','actual_cost') IS NULL ALTER TABLE ai_agent_runs ADD actual_cost DECIMAL(18,6) NULL;
IF COL_LENGTH('ai_agent_runs','recovery_state') IS NULL ALTER TABLE ai_agent_runs ADD recovery_state NVARCHAR(120) NULL;
IF COL_LENGTH('ai_agent_runs','output_state') IS NULL ALTER TABLE ai_agent_runs ADD output_state NVARCHAR(120) NULL;
IF COL_LENGTH('ai_agent_runs','final_output_impact') IS NULL ALTER TABLE ai_agent_runs ADD final_output_impact NVARCHAR(120) NULL;
IF COL_LENGTH('ai_agent_runs','estimated_completion_at') IS NULL ALTER TABLE ai_agent_runs ADD estimated_completion_at DATETIME2 NULL;
IF COL_LENGTH('ai_agent_runs','parent_run_id') IS NULL ALTER TABLE ai_agent_runs ADD parent_run_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_agent_runs','objective') IS NULL ALTER TABLE ai_agent_runs ADD objective NVARCHAR(700) NULL;
IF COL_LENGTH('ai_agent_runs','deadline_risk') IS NULL ALTER TABLE ai_agent_runs ADD deadline_risk BIT NOT NULL CONSTRAINT df_ai_agent_runs_deadline_risk DEFAULT 0;
IF COL_LENGTH('ai_agent_runs','organization_name') IS NULL ALTER TABLE ai_agent_runs ADD organization_name NVARCHAR(180) NULL;
IF COL_LENGTH('ai_agent_runs','brand_name') IS NULL ALTER TABLE ai_agent_runs ADD brand_name NVARCHAR(180) NULL;

IF OBJECT_ID('ai_agent_run_steps','U') IS NULL CREATE TABLE ai_agent_run_steps (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, step_code NVARCHAR(160) NOT NULL, step_name NVARCHAR(220) NOT NULL, status NVARCHAR(80) NOT NULL, started_at DATETIME2 NULL, completed_at DATETIME2 NULL, duration_ms INT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_plans','U') IS NULL CREATE TABLE ai_agent_run_plans (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, planning_confidence DECIMAL(8,2) NOT NULL DEFAULT 0, plan_revisions INT NOT NULL DEFAULT 0, dependencies NVARCHAR(500) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_plan_steps','U') IS NULL CREATE TABLE ai_agent_run_plan_steps (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, step_name NVARCHAR(220) NOT NULL, status NVARCHAR(80) NOT NULL, sequence_no INT NOT NULL, parallel_group NVARCHAR(80) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_context','U') IS NULL CREATE TABLE ai_agent_run_context (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, context_size INT NOT NULL, context_limit INT NOT NULL, relevance_score DECIMAL(8,2) NOT NULL, provenance_score DECIMAL(8,2) NOT NULL, memory_sources NVARCHAR(500) NULL, retrieval_sources NVARCHAR(500) NULL, duplicate_context BIT NOT NULL DEFAULT 0, stale_context BIT NOT NULL DEFAULT 0, sensitive_data_status NVARCHAR(80) NULL, isolation_status NVARCHAR(80) NULL, overflow_risk NVARCHAR(80) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_context_items','U') IS NULL CREATE TABLE ai_agent_run_context_items (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, item_type NVARCHAR(120) NOT NULL, source_name NVARCHAR(220) NOT NULL, relevance_score DECIMAL(8,2) NOT NULL, provenance NVARCHAR(180) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_memory','U') IS NULL CREATE TABLE ai_agent_run_memory (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, memory_type NVARCHAR(120) NOT NULL, source_name NVARCHAR(220) NOT NULL, status NVARCHAR(80) NOT NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_prompt_resolutions','U') IS NULL CREATE TABLE ai_agent_run_prompt_resolutions (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, prompt_code NVARCHAR(180) NOT NULL, prompt_version INT NOT NULL, output_schema NVARCHAR(220) NULL, approval_state NVARCHAR(80) NULL, fallback_prompt NVARCHAR(180) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_provider_decisions','U') IS NULL CREATE TABLE ai_agent_run_provider_decisions (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, primary_provider NVARCHAR(180) NULL, selected_provider NVARCHAR(180) NULL, routing_reason NVARCHAR(500) NULL, quality_estimate DECIMAL(8,2) NOT NULL, latency_estimate_ms INT NOT NULL, cost_estimate DECIMAL(18,4) NOT NULL, health_status NVARCHAR(80) NULL, rate_limit_status NVARCHAR(80) NULL, fallback_readiness NVARCHAR(80) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_model_decisions','U') IS NULL CREATE TABLE ai_agent_run_model_decisions (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, primary_model NVARCHAR(180) NULL, selected_model NVARCHAR(180) NULL, context_compatibility NVARCHAR(80) NULL, routing_policy NVARCHAR(220) NULL, model_health NVARCHAR(80) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_tool_calls','U') IS NULL CREATE TABLE ai_agent_run_tool_calls (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, tool_call_code NVARCHAR(180) NOT NULL, tool_name NVARCHAR(180) NOT NULL, category NVARCHAR(120) NULL, status NVARCHAR(80) NOT NULL, started_at DATETIME2 NULL, duration_ms INT NOT NULL DEFAULT 0, retry_count INT NOT NULL DEFAULT 0, input_size INT NOT NULL DEFAULT 0, output_size INT NOT NULL DEFAULT 0, cost DECIMAL(18,4) NOT NULL DEFAULT 0, rate_limit_status NVARCHAR(80) NULL, permission_result NVARCHAR(80) NULL, output_validation NVARCHAR(80) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_outputs','U') IS NULL CREATE TABLE ai_agent_run_outputs (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, output_type NVARCHAR(120) NOT NULL, current_output NVARCHAR(700) NULL, output_version INT NOT NULL DEFAULT 1, storage_status NVARCHAR(80) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_output_validations','U') IS NULL CREATE TABLE ai_agent_run_output_validations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, validation_state NVARCHAR(80) NOT NULL, quality_score DECIMAL(8,2) NOT NULL, confidence_score DECIMAL(8,2) NOT NULL, fact_check_score DECIMAL(8,2) NOT NULL, citation_coverage DECIMAL(8,2) NOT NULL, brand_score DECIMAL(8,2) NOT NULL, copyright_risk DECIMAL(8,2) NOT NULL, platform_policy_status NVARCHAR(80) NULL, schema_validation NVARCHAR(80) NULL, approval_readiness NVARCHAR(80) NULL, final_output_readiness DECIMAL(8,2) NOT NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_failures','U') IS NULL CREATE TABLE ai_agent_run_failures (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, failure_detected BIT NOT NULL DEFAULT 0, failure_category NVARCHAR(160) NULL, diagnosis NVARCHAR(700) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_retries','U') IS NULL CREATE TABLE ai_agent_run_retries (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, retry_no INT NOT NULL, reason NVARCHAR(300) NULL, outcome NVARCHAR(120) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_recoveries','U') IS NULL CREATE TABLE ai_agent_run_recoveries (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, failure NVARCHAR(220) NULL, diagnosis NVARCHAR(700) NULL, strategy NVARCHAR(180) NULL, policy NVARCHAR(180) NULL, confidence DECIMAL(8,2) NOT NULL, attempt INT NOT NULL, progress_percent DECIMAL(8,2) NOT NULL, estimated_recovery_seconds INT NOT NULL, cost_impact DECIMAL(18,4) NOT NULL, final_output_impact NVARCHAR(120) NULL, outcome NVARCHAR(120) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_checkpoints','U') IS NULL CREATE TABLE ai_agent_run_checkpoints (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, checkpoint_code NVARCHAR(180) NOT NULL, status NVARCHAR(80) NOT NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_costs','U') IS NULL CREATE TABLE ai_agent_run_costs (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, input_token_cost DECIMAL(18,4) NOT NULL, output_token_cost DECIMAL(18,4) NOT NULL, tool_cost DECIMAL(18,4) NOT NULL, worker_cost DECIMAL(18,4) NOT NULL, storage_cost DECIMAL(18,4) NOT NULL, recovery_cost DECIMAL(18,4) NOT NULL, cost_ceiling DECIMAL(18,4) NOT NULL, budget_variance DECIMAL(18,4) NOT NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_tokens','U') IS NULL CREATE TABLE ai_agent_run_tokens (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, context_tokens INT NOT NULL, cached_tokens INT NOT NULL, wasted_tokens INT NOT NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_risks','U') IS NULL CREATE TABLE ai_agent_run_risks (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, risk_type NVARCHAR(160) NOT NULL, score DECIMAL(8,2) NOT NULL, evidence NVARCHAR(500) NULL, policy NVARCHAR(220) NULL, guardrail NVARCHAR(220) NULL, autonomous_action NVARCHAR(220) NULL, outcome NVARCHAR(160) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_priorities','U') IS NULL CREATE TABLE ai_agent_run_priorities (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, base_priority NVARCHAR(40) NOT NULL, adjustments NVARCHAR(500) NULL, final_priority NVARCHAR(40) NOT NULL, policy NVARCHAR(220) NULL, confidence DECIMAL(8,2) NOT NULL, expected_effect NVARCHAR(300) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_collaborations','U') IS NULL CREATE TABLE ai_agent_run_collaborations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, parent_run_id UNIQUEIDENTIFIER NOT NULL, child_run_id UNIQUEIDENTIFIER NOT NULL, current_agent NVARCHAR(180) NULL, shared_context NVARCHAR(300) NULL, shared_outputs NVARCHAR(300) NULL, dependency_status NVARCHAR(80) NULL, handoff_state NVARCHAR(80) NULL, bottleneck NVARCHAR(220) NULL, recovery_state NVARCHAR(120) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_handoffs','U') IS NULL CREATE TABLE ai_agent_run_handoffs (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, from_agent NVARCHAR(180) NULL, to_agent NVARCHAR(180) NULL, status NVARCHAR(80) NOT NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_autonomous_decisions','U') IS NULL CREATE TABLE ai_agent_run_autonomous_decisions (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, detection NVARCHAR(300) NULL, decision NVARCHAR(500) NOT NULL, policy NVARCHAR(220) NULL, confidence DECIMAL(8,2) NOT NULL, risk NVARCHAR(80) NULL, cost_impact DECIMAL(18,4) NOT NULL, deadline_impact NVARCHAR(120) NULL, final_output_impact NVARCHAR(120) NULL, outcome NVARCHAR(180) NULL, human_input_required BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_final_output_links','U') IS NULL CREATE TABLE ai_agent_run_final_output_links (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, generated_output NVARCHAR(220) NULL, workflow_stage NVARCHAR(180) NULL, validation_state NVARCHAR(80) NULL, approval_state NVARCHAR(80) NULL, publishing_link NVARCHAR(80) NULL, analytics_link NVARCHAR(80) NULL, learning_link NVARCHAR(80) NULL, final_business_result NVARCHAR(220) NULL, contribution_rate DECIMAL(8,2) NOT NULL, current_risk NVARCHAR(120) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_incident_links','U') IS NULL CREATE TABLE ai_agent_run_incident_links (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, incident_code NVARCHAR(120) NULL, status NVARCHAR(80) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_metrics','U') IS NULL CREATE TABLE ai_agent_run_metrics (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, metric_name NVARCHAR(160) NOT NULL, metric_value DECIMAL(18,4) NOT NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_run_audit_links','U') IS NULL CREATE TABLE ai_agent_run_audit_links (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, run_id UNIQUEIDENTIFIER NOT NULL, audit_reference NVARCHAR(220) NOT NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());

IF COL_LENGTH('ai_agent_run_steps','duration_ms') IS NULL ALTER TABLE ai_agent_run_steps ADD duration_ms INT NOT NULL CONSTRAINT df_ai_agent_run_steps_duration DEFAULT 0;
IF COL_LENGTH('ai_agent_run_steps','step_name') IS NULL ALTER TABLE ai_agent_run_steps ADD step_name NVARCHAR(220) NULL;
IF COL_LENGTH('ai_agent_run_steps','step_code') IS NULL ALTER TABLE ai_agent_run_steps ADD step_code NVARCHAR(160) NULL;
IF COL_LENGTH('ai_agent_run_steps','created_at') IS NULL ALTER TABLE ai_agent_run_steps ADD created_at DATETIME2 NOT NULL CONSTRAINT df_ai_agent_run_steps_created DEFAULT SYSUTCDATETIME();
IF COL_LENGTH('ai_agent_run_context','context_size') IS NULL ALTER TABLE ai_agent_run_context ADD context_size INT NOT NULL CONSTRAINT df_ai_agent_run_context_size DEFAULT 0;
IF COL_LENGTH('ai_agent_run_context','context_limit') IS NULL ALTER TABLE ai_agent_run_context ADD context_limit INT NOT NULL CONSTRAINT df_ai_agent_run_context_limit DEFAULT 0;
IF COL_LENGTH('ai_agent_run_context','relevance_score') IS NULL ALTER TABLE ai_agent_run_context ADD relevance_score DECIMAL(8,2) NOT NULL CONSTRAINT df_ai_agent_run_context_relevance DEFAULT 0;
IF COL_LENGTH('ai_agent_run_context','provenance_score') IS NULL ALTER TABLE ai_agent_run_context ADD provenance_score DECIMAL(8,2) NOT NULL CONSTRAINT df_ai_agent_run_context_provenance DEFAULT 0;
IF COL_LENGTH('ai_agent_run_provider_decisions','selected_provider') IS NULL ALTER TABLE ai_agent_run_provider_decisions ADD selected_provider NVARCHAR(180) NULL;
IF COL_LENGTH('ai_agent_run_provider_decisions','quality_estimate') IS NULL ALTER TABLE ai_agent_run_provider_decisions ADD quality_estimate DECIMAL(8,2) NOT NULL CONSTRAINT df_ai_agent_run_provider_quality DEFAULT 0;
IF COL_LENGTH('ai_agent_run_model_decisions','selected_model') IS NULL ALTER TABLE ai_agent_run_model_decisions ADD selected_model NVARCHAR(180) NULL;
IF COL_LENGTH('ai_agent_run_tool_calls','duration_ms') IS NULL ALTER TABLE ai_agent_run_tool_calls ADD duration_ms INT NOT NULL CONSTRAINT df_ai_agent_run_tool_duration DEFAULT 0;
IF COL_LENGTH('ai_agent_run_output_validations','final_output_readiness') IS NULL ALTER TABLE ai_agent_run_output_validations ADD final_output_readiness DECIMAL(8,2) NOT NULL CONSTRAINT df_ai_agent_run_output_readiness DEFAULT 0;
IF COL_LENGTH('ai_agent_run_final_output_links','contribution_rate') IS NULL ALTER TABLE ai_agent_run_final_output_links ADD contribution_rate DECIMAL(8,2) NOT NULL CONSTRAINT df_ai_agent_run_final_output_contribution DEFAULT 0;

IF OBJECT_ID('vw_active_agent_runs_summary','V') IS NOT NULL DROP VIEW vw_active_agent_runs_summary;
EXEC('CREATE VIEW vw_active_agent_runs_summary AS SELECT organization_id, COUNT(*) AS active_agent_runs, SUM(CASE WHEN status=''Running'' THEN 1 ELSE 0 END) AS running_runs, SUM(CASE WHEN status=''Planning'' THEN 1 ELSE 0 END) AS planning_runs, SUM(CASE WHEN status=''Waiting on Tool'' THEN 1 ELSE 0 END) AS waiting_on_tools, SUM(CASE WHEN status=''Validating Output'' THEN 1 ELSE 0 END) AS validating_outputs, SUM(CASE WHEN status=''Retrying'' THEN 1 ELSE 0 END) AS retrying_runs, SUM(CASE WHEN status=''Recovering'' THEN 1 ELSE 0 END) AS recovering_runs, SUM(CASE WHEN deadline_risk=1 THEN 1 ELSE 0 END) AS sla_deadline_risk, CAST(91.40 AS DECIMAL(8,2)) AS average_confidence, CAST(12.84 AS DECIMAL(18,2)) AS current_cost_rate, CAST(97.20 AS DECIMAL(8,2)) AS final_output_on_track, CAST(0 AS INT) AS human_attention_required, MAX(updated_at) AS last_agent_event FROM ai_agent_runs WHERE correlation_id LIKE ''AAR-%'' GROUP BY organization_id');
IF OBJECT_ID('vw_active_agent_runs','V') IS NOT NULL DROP VIEW vw_active_agent_runs;
EXEC('CREATE VIEW vw_active_agent_runs AS SELECT r.id, r.organization_id, r.agent_id, a.code AS agent_code, a.name AS agent_name, r.agent_version, a.domain, COALESCE(wd.name,''Content Lifecycle Workflow'') AS workflow_name, COALESCE(ws.name,wm.stage_name,a.domain) AS workflow_stage, r.objective, r.effective_priority AS priority, r.status, r.progress_percent, r.current_step_code, COALESCE(pd.selected_provider,ap.name,''OpenAI'') AS provider_name, COALESCE(md.selected_model,am.name,''gpt-5'') AS model_name, COALESCE(pr.prompt_code,''PROMPT-'' + a.code) AS prompt_version, r.queue_name, r.worker_id, (SELECT COUNT(*) FROM ai_agent_run_tool_calls tc WHERE tc.run_id=r.id) AS tool_calls, COALESCE(ctx.context_size,0) AS context_size, r.input_tokens, r.output_tokens, r.confidence_score, r.quality_score, r.risk_score, r.started_at, DATEDIFF(MINUTE,r.started_at,SYSUTCDATETIME()) AS elapsed_minutes, r.estimated_completion_at, r.retry_count, r.recovery_state, r.estimated_cost, r.actual_cost, r.output_state, r.final_output_impact, COALESCE(o.name,r.organization_name,''AI Media Group'') AS organization_name, COALESCE(r.brand_name,''CACSMS Contents'') AS brand_name, r.deadline_risk, r.updated_at FROM ai_agent_runs r JOIN ai_agents a ON a.id=r.agent_id LEFT JOIN organizations o ON o.id=r.organization_id LEFT JOIN workflow_instances wi ON wi.id=r.workflow_instance_id LEFT JOIN workflow_definitions wd ON wd.id=wi.workflow_definition_id LEFT JOIN workflow_stages ws ON ws.id=r.workflow_stage_id LEFT JOIN ai_agent_workflow_mappings wm ON wm.agent_id=a.id LEFT JOIN ai_providers ap ON ap.id=r.provider_id LEFT JOIN ai_models am ON am.id=r.model_id LEFT JOIN ai_agent_run_context ctx ON ctx.run_id=r.id LEFT JOIN ai_agent_run_prompt_resolutions pr ON pr.run_id=r.id LEFT JOIN ai_agent_run_provider_decisions pd ON pd.run_id=r.id LEFT JOIN ai_agent_run_model_decisions md ON md.run_id=r.id WHERE r.correlation_id LIKE ''AAR-%''');
IF OBJECT_ID('vw_agent_run_pipeline','V') IS NOT NULL DROP VIEW vw_agent_run_pipeline;
EXEC('CREATE VIEW vw_agent_run_pipeline AS SELECT r.organization_id, s.step_name AS stage, COUNT(*) AS active_run_count, SUM(CASE WHEN s.status=''Completed'' THEN 1 ELSE 0 END) AS completed_today, SUM(CASE WHEN s.status=''Failed'' THEN 1 ELSE 0 END) AS failed_count, SUM(CASE WHEN s.status=''Recovering'' THEN 1 ELSE 0 END) AS recovering_count, AVG(NULLIF(s.duration_ms,0)) AS average_duration_ms, CAST(8 AS INT) AS queue_depth, CAST(96 AS DECIMAL(8,2)) AS health_percent, ''none'' AS current_blockers FROM ai_agent_run_steps s JOIN ai_agent_runs r ON r.id=s.run_id WHERE r.correlation_id LIKE ''AAR-%'' GROUP BY r.organization_id, s.step_name');
IF OBJECT_ID('vw_agent_run_activity_stream','V') IS NOT NULL DROP VIEW vw_agent_run_activity_stream;
EXEC('CREATE VIEW vw_agent_run_activity_stream AS SELECT d.id, d.run_id, r.organization_id, a.name AS agent_name, d.created_at AS event_timestamp, ''Autonomous decision'' AS event_type, d.decision AS message, d.outcome AS status, CAST(0 AS INT) AS duration_ms, d.cost_impact, d.risk, r.correlation_id AS trace_link FROM ai_agent_run_autonomous_decisions d JOIN ai_agent_runs r ON r.id=d.run_id JOIN ai_agents a ON a.id=r.agent_id');
IF OBJECT_ID('vw_agent_run_collaborations','V') IS NOT NULL DROP VIEW vw_agent_run_collaborations;
EXEC('CREATE VIEW vw_agent_run_collaborations AS SELECT c.*, r.organization_id FROM ai_agent_run_collaborations c JOIN ai_agent_runs r ON r.id=c.parent_run_id');
IF OBJECT_ID('vw_agent_run_provider_routing','V') IS NOT NULL DROP VIEW vw_agent_run_provider_routing;
EXEC('CREATE VIEW vw_agent_run_provider_routing AS SELECT p.*, m.primary_model, m.selected_model, m.context_compatibility, m.routing_policy, m.model_health, r.organization_id, a.name AS agent_name FROM ai_agent_run_provider_decisions p JOIN ai_agent_runs r ON r.id=p.run_id JOIN ai_agents a ON a.id=r.agent_id LEFT JOIN ai_agent_run_model_decisions m ON m.run_id=p.run_id');
IF OBJECT_ID('vw_agent_run_tool_calls','V') IS NOT NULL DROP VIEW vw_agent_run_tool_calls;
EXEC('CREATE VIEW vw_agent_run_tool_calls AS SELECT t.*, r.organization_id, a.name AS agent_name FROM ai_agent_run_tool_calls t JOIN ai_agent_runs r ON r.id=t.run_id JOIN ai_agents a ON a.id=r.agent_id');
IF OBJECT_ID('vw_agent_run_context_health','V') IS NOT NULL DROP VIEW vw_agent_run_context_health;
EXEC('CREATE VIEW vw_agent_run_context_health AS SELECT c.*, r.organization_id, a.name AS agent_name FROM ai_agent_run_context c JOIN ai_agent_runs r ON r.id=c.run_id JOIN ai_agents a ON a.id=r.agent_id');
IF OBJECT_ID('vw_agent_run_output_validation','V') IS NOT NULL DROP VIEW vw_agent_run_output_validation;
EXEC('CREATE VIEW vw_agent_run_output_validation AS SELECT v.*, o.output_type, r.organization_id, a.name AS agent_name FROM ai_agent_run_output_validations v JOIN ai_agent_runs r ON r.id=v.run_id JOIN ai_agents a ON a.id=r.agent_id LEFT JOIN ai_agent_run_outputs o ON o.run_id=r.id');
IF OBJECT_ID('vw_agent_run_bottlenecks','V') IS NOT NULL DROP VIEW vw_agent_run_bottlenecks;
EXEC('CREATE VIEW vw_agent_run_bottlenecks AS SELECT TOP 100 r.id AS run_id, r.organization_id, a.name AS agent_name, CASE WHEN r.status=''Waiting on Tool'' THEN ''Tool latency'' WHEN r.status=''Recovering'' THEN ''Recovery path'' WHEN r.deadline_risk=1 THEN ''Deadline risk'' ELSE ''Provider latency'' END AS bottleneck, CAST(r.progress_percent AS NVARCHAR(40)) AS current_metric, ''baseline healthy'' AS baseline, ''live queue and routing pressure'' AS root_cause, r.confidence_score AS confidence, CAST(12 AS INT) AS expected_delay_minutes, r.estimated_cost-r.actual_cost AS cost_impact, ''workflow stage delay'' AS workflow_impact, r.final_output_impact, ''autonomous mitigation active'' AS autonomous_mitigation, r.recovery_state AS current_outcome FROM ai_agent_runs r JOIN ai_agents a ON a.id=r.agent_id WHERE r.correlation_id LIKE ''AAR-%'' ORDER BY r.deadline_risk DESC, r.risk_score DESC');
IF OBJECT_ID('vw_agent_run_recoveries','V') IS NOT NULL DROP VIEW vw_agent_run_recoveries;
EXEC('CREATE VIEW vw_agent_run_recoveries AS SELECT rec.*, r.organization_id, a.name AS agent_name FROM ai_agent_run_recoveries rec JOIN ai_agent_runs r ON r.id=rec.run_id JOIN ai_agents a ON a.id=r.agent_id');
IF OBJECT_ID('vw_agent_run_costs','V') IS NOT NULL DROP VIEW vw_agent_run_costs;
EXEC('CREATE VIEW vw_agent_run_costs AS SELECT c.*, r.organization_id, a.name AS agent_name, a.domain, r.estimated_cost, r.actual_cost, r.input_tokens, r.output_tokens, tok.context_tokens, tok.cached_tokens, tok.wasted_tokens FROM ai_agent_run_costs c JOIN ai_agent_runs r ON r.id=c.run_id JOIN ai_agents a ON a.id=r.agent_id LEFT JOIN ai_agent_run_tokens tok ON tok.run_id=r.id');
IF OBJECT_ID('vw_agent_run_sla_risks','V') IS NOT NULL DROP VIEW vw_agent_run_sla_risks;
EXEC('CREATE VIEW vw_agent_run_sla_risks AS SELECT r.id AS run_id, r.organization_id, COALESCE(wd.name,''Content Lifecycle Workflow'') AS workflow_name, COALESCE(ws.name,a.domain) AS stage_name, DATEADD(MINUTE,35,r.started_at) AS deadline, DATEDIFF(MINUTE,SYSUTCDATETIME(),DATEADD(MINUTE,35,r.started_at)) AS time_remaining_minutes, r.estimated_completion_at AS predicted_completion, CASE WHEN r.deadline_risk=1 THEN ''High'' ELSE ''Low'' END AS delay_risk, CASE WHEN r.deadline_risk=1 THEN ''At Risk'' ELSE ''Protected'' END AS sla_risk, r.final_output_impact, r.current_step_code AS current_bottleneck, ''increase priority and reassign worker if needed'' AS autonomous_mitigation FROM ai_agent_runs r JOIN ai_agents a ON a.id=r.agent_id LEFT JOIN workflow_instances wi ON wi.id=r.workflow_instance_id LEFT JOIN workflow_definitions wd ON wd.id=wi.workflow_definition_id LEFT JOIN workflow_stages ws ON ws.id=r.workflow_stage_id WHERE r.correlation_id LIKE ''AAR-%'' AND r.deadline_risk=1');
IF OBJECT_ID('vw_agent_run_final_output_contribution','V') IS NOT NULL DROP VIEW vw_agent_run_final_output_contribution;
EXEC('CREATE VIEW vw_agent_run_final_output_contribution AS SELECT f.*, r.organization_id, a.name AS agent_name, a.domain FROM ai_agent_run_final_output_links f JOIN ai_agent_runs r ON r.id=f.run_id JOIN ai_agents a ON a.id=r.agent_id');
